          <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>text-sm leading-5<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
